#[derive(Debug, Clone, Copy)]
pub struct AtlasEntry {
    pub ra_rad: f64,
    pub dec_rad: f64,
    pub unit: [f64; 3],
    pub mag_g: f64,
    pub bp_rp: f64,
    pub pm_ra: f64,
    pub pm_dec: f64,
    pub hip_id: u32,
    pub source_id: u64,
}

pub fn get_visible_stars(lat: f64, lon: f64, jd: f64, alt_limit: f64) -> Vec<AtlasEntry> {
    let mut visible = Vec::new();
    let lst = get_lst(lon, jd);
    
    for entry in BRIGHT_ATLAS {
        let alt = get_altitude(entry.ra_rad, entry.dec_rad, lat, lst);
        if alt > alt_limit {
            visible.push(entry.clone());
        }
    }
    visible
}

fn get_lst(lon: f64, jd: f64) -> f64 {
    let d = jd - 2451545.0;
    let lst = (18.697374558 + 24.06570982441908 * d) % 24.0;
    (lst * 15.0).to_radians() + lon
}

fn get_altitude(ra: f64, dec: f64, lat: f64, lst: f64) -> f64 {
    let ha = lst - ra;
    let sin_alt = lat.sin() * dec.sin() + lat.cos() * dec.cos() * ha.cos();
    sin_alt.asin()
}

